	private static void assertDifferent(String field, QueryModelNode left, QueryModelNode right) {
		assertFalse(ExactTreeEquality.equal(left, right), () -> field + " was ignored");
	}

	private static void assertSame(String field, QueryModelNode left, QueryModelNode right) {
		assertTrue(ExactTreeEquality.equal(left, right), () -> field + " rejected equal semantic values");
	}

	private static ArbitraryLengthPath fixedSelfPath(long minLength) {
		Var start = Var.of("path-start", SUBJECT);
		Var end = Var.of("path-end", SUBJECT);
		StatementPattern step = new StatementPattern(
				start.clone(),
				Var.of("path-predicate", PREDICATE),
				end.clone());
		return new MinLengthBlindPath(start, step, end, minLength);
	}

