	/** Emulates an RDF4J node equality implementation that omits {@code minLength}. */
	private static final class MinLengthBlindPath extends ArbitraryLengthPath {
		private MinLengthBlindPath(Var subject, StatementPattern pathExpression, Var object, long minLength) {
			super(subject, pathExpression, object, minLength);
		}

		@Override
		public boolean equals(Object other) {
			if (other instanceof MinLengthBlindPath path) {
				return getSubjectVar().equals(path.getSubjectVar())
						&& getPathExpression().equals(path.getPathExpression())
						&& getObjectVar().equals(path.getObjectVar())
						&& getScope() == path.getScope();
			}
			return false;
		}

		@Override
		public int hashCode() {
			return getSubjectVar().hashCode()
					^ getPathExpression().hashCode()
					^ getObjectVar().hashCode()
					^ getScope().hashCode();
		}
	}
